module shift_register_16bit (q, clk, reset, sh_en, ld_en, d);
   input clk, reset, sh_en, ld_en;
   input [15:0] d;
   output [15:0] q;

   reg [15:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        q <= 16'b0;
    else if (ld_en)
        q <= d;
    else if (sh_en)
        q <= q << 1;
end

endmodule
